preview_components.import_syntax:
// Preview components require the preview__ prefix in imports
import { preview__IconIndicator as IconIndicator } from '@carbon/react';
import { preview__Dialog as Dialog } from '@carbon/react';

package.import_pattern:
import { Button, TextInput, Grid, Column } from '@carbon/react';

// Preview components require special import syntax
import { preview__IconIndicator as IconIndicator } from '@carbon/react';

import { Add, Edit, Delete, ArrowRight } from '@carbon/icons-react';

// Usage in components
<Button renderIcon={Add}>Add Item</Button>

rule.status_indicators:
Communicate state — "what is happening?" Use IconIndicator or ShapeIndicator.
Kinds: failed, warning, caution, succeeded, in-progress, pending, etc.
Import: import { preview__IconIndicator as IconIndicator } from '@carbon/react';

layer_system.usage_example:
import { Layer } from '@carbon/react';
// Correct: Nesting determines layer level <> <ComponentOnBaseLayer /> <Layer withBackground> <ComponentOnLayer01 /> <Layer withBackground> <ComponentOnLayer02 /> </Layer> </Layer> </>
// Incorrect: Don't manually set level <Layer level={2}> {/* ❌ Don't do this */} <ComponentOnLayer02 /> </Layer>

pattern.code:
import { Modal } from '@carbon/react';

<Modal
open={isOpen}
onRequestClose={() => setIsOpen(false)}
modalHeading="Confirm Action" primaryButtonText="Confirm" secondaryButtonText="Cancel">
<p>Are you sure you want to proceed?</p>
</Modal>
